import io
import re
import base64
import hashlib
from PIL import Image


# ─── Image resize helper ──────────────────────────────────────────────────────
def resize_image(file_obj, max_w: int = 720, max_h: int = 540, quality: int = 82) -> bytes:
    img = Image.open(file_obj).convert("RGB")
    img.thumbnail((max_w, max_h), Image.LANCZOS)
    buf = io.BytesIO()
    img.save(buf, format="JPEG", quality=quality, optimize=True)
    return buf.getvalue()


# ─── Base64 photo helper ──────────────────────────────────────────────────────
def photo_html(
    photo_bytes,
    width: str = "100%",
    height: str = "160px",
    radius: str = "8px",
    placeholder_text: str = "No photo",
) -> str:
    if photo_bytes:
        b64 = base64.b64encode(photo_bytes).decode()
        return (
            f'<div style="width:{width};height:{height};overflow:hidden;'
            f'border-radius:{radius};background:#F1F3F5;flex-shrink:0;'
            f'display:flex;align-items:center;justify-content:center;">'
            f'<img src="data:image/jpeg;base64,{b64}" '
            f'style="width:100%;height:100%;object-fit:contain;display:block;" /></div>'
        )
    return (
        f'<div style="width:{width};height:{height};overflow:hidden;'
        f'border-radius:{radius};background:#F1F3F5;display:flex;'
        f'align-items:center;justify-content:center;'
        f'font-size:.72rem;color:#9CA3AF;flex-shrink:0;letter-spacing:.03em;">'
        f'{placeholder_text}</div>'
    )


