def icon_html(name: str, size: int = 16, color: str = "currentColor", style: str = "") -> str:
    return f'<span style="display:inline-flex;align-items:center;vertical-align:middle;{style}">{icon(name, size, color)}</span>'


# ─── Auth helpers ─────────────────────────────────────────────────────────────
EMAIL_PATTERN = re.compile(r"^\d{4}-\d{6}@rtu\.edu\.ph$", re.IGNORECASE)


def _hash(pw: str) -> str:
    return hashlib.sha256(pw.encode()).hexdigest()


