# ─── Badge renderer ───────────────────────────────────────────────────────────
def badge(status: str) -> str:
    status_icons = {
        "lost":     "alert-circle",
        "found":    "box",
        "claimed":  "check-circle",
        "pending":  "clock",
        "approved": "check-circle",
        "rejected": "x",
    }
    colors = {
        "lost":     "#991B1B",
        "found":    "#164EC6",
        "claimed":  "#166534",
        "pending":  "#92400E",
        "approved": "#166534",
        "rejected": "#991B1B",
    }
    ico = status_icons.get(status, "info")
    c   = colors.get(status, "#374151")
    return f'<span class="badge badge-{status}">{icon(ico, 10, c)}&nbsp;{status.upper()}</span>'


# ─── Text helpers ─────────────────────────────────────────────────────────────
def truncate(text: str, limit: int = 100) -> str:
    return text[:limit].rstrip() + "…" if len(text) > limit else text
